(578, 'Mont Blanc MB0278S', 'Mont Blanc', 'Sunglasses', 520.00, NULL, '[https://www.framesdirect.com/product_color_images/Mont-Blanc-sun-MB0278S-silver-silver-001.jpg, https://www.framesdirect.com/product_color_images/Mont-Blanc-sun-MB0278S-gunmetal-gunmetal-003.jpg, https://www.framesdirect.com/product_color_images/Mont-Blanc-sun-MB0278S-silver-silver-001.jpg]', 'Free Shipping & Easy Returns! Explore Mont Blanc MB0278S Sunglasses now.', 'https://www.framesdirect.com/mont-blanc-mb0278s-sunglasses', NULL, NULL),
(579, 'Harley-Davidson HD0977X', 'Harley-Davidson', 'Sunglasses', 130.00, NULL, '[https://www.framesdirect.com/product_color_images/harley-davidson-sun-HD0977X-01D.jpg, https://www.framesdirect.com/product_color_images/harley-davidson-sun-HD0977X-52R.jpg]', 'Free Shipping & Easy Returns, plus Price Match! Explore Harley-Davidson HD0977X Sunglasses now and enjoy the latest promotions on Harley-Davidson frames. Our Harley-Davidson optical and sunwear collections embody the gritty appeal of Harley-Davidson and the sharp, stylish designs of a culture that truly represents cutting edge American fashion. The Harley-Davidson collection pays homage to iconic American styles while adding its own twists and accents. Most frames come with either a classic Harley-Davidson bar-and-shield logo or with the Willie G. skull collection logo. Harley-Davidson offers a variety of frame shapes and colors in order for each Harley rider and fanatic to clearly express what styles drives them.', 'https://www.framesdirect.com/harley-davidson-hd0977x-sunglasses', NULL, NULL),
