(590, 'Dolce & Gabbana Kids DX4003', 'Dolce & Gabbana Kids', 'Sunglasses', 184.00, NULL, '[https://www.framesdirect.com/product_color_images/Dolce-Gabbana-DX4003-300880-Sunglasses_030A.jpg, https://www.framesdirect.com/product_color_images/Dolce-Gabbana-DX4003-340971-Sunglasses_030A.jpg]', 'Free Shipping & Easy Returns, plus Price Match! Explore Dolce & Gabbana Kids DX4003 Sunglasses now.', 'https://www.framesdirect.com/dolce-gabbana-kids-dx4003-sunglasses', NULL, NULL),
(591, 'Nike Jolt M DZ7379', 'Nike', 'Sunglasses', 125.00, NULL, '[https://www.framesdirect.com/product_color_images/Nike-Jolt-M-DZ7379-402-Green-Mirror-Sunglasses.jpg, https://www.framesdirect.com/product_color_images/Nike-Jolt-M-DZ7379-100-Blue-Mirror-Sunglasses.jpg]', 'Free Shipping & Easy Returns, plus Price Match! Explore Nike Jolt M DZ7379 Sunglasses now and enjoy the latest promotions on Nike frames. The Nike eyewear collection offers the same dependability as the brand’s celebrated sports apparel and equipment. These frames come with innovative performance features to outfit your lifestyle. Find athletic eyewear for men, women, and children—including sunglasses customized with lenses in your prescription—eyewear that’s designed to keep up on any adventure. Excellence in design is part of Nike’s commitment to its customers. Men, women, and children count on this global name for their eyewear, for sports and for everyday performance.', 'https://www.framesdirect.com/nike-jolt-m-dz7379-sunglasses', NULL, NULL),
